    concepts: ["sum formula", "O(n) algorithm", "arithmetic sequence", "set difference"],
    codeExample: `def find_missing(nums, n):
    expected = n * (n + 1) // 2
    return expected - sum(nums)

def find_missing_set(nums, n):
    full_set = set(range(1, n + 1))
    return (full_set - set(nums)).pop()

data = [1, 2, 4, 5, 6]
print(find_missing(data, 6))
print(find_missing_set(data, 6))`,
