    concepts: ["quiz logic", "list of dicts", "score tracking", "string comparison"],
    codeExample: `class Quiz:
    def __init__(self):
        self.questions = []
        self.score = 0

    def add_question(self, text, answer):
        self.questions.append({"q": text, "a": answer.lower()})

    def attempt(self, index, user_answer):
        q = self.questions[index]
        if user_answer.lower() == q["a"]:
            self.score += 1
            return "Correct!"
        return f"Wrong. Answer: {q['a']}"

    def result(self):
        total = len(self.questions)
        return f"Score: {self.score}/{total}"

quiz = Quiz()
quiz.add_question("Capital of France?", "paris")
quiz.add_question("2 + 2 = ?", "4")
quiz.add_question("What language is this?", "python")

print(quiz.attempt(0, "Paris"))
print(quiz.attempt(1, "5"))
print(quiz.attempt(2, "Python"))
print(quiz.result())`,
