    concepts: ["decorator chaining", "decorator order", "wraps", "functools.wraps"],
    codeExample: `from functools import wraps

def shout(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        result = fn(*args, **kwargs)
        return result.upper()
    return wrapper

def exclaim(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        return fn(*args, **kwargs) + "!!!"
    return wrapper

@shout
@exclaim
def greet(name):
    return f"hello {name}"

print(greet("world"))
print(greet.__name__)`,
