          hint: "const history=[]; _show() pushes {id,type,title,msg,time:Date.now(),read:false} to history. Bell badge: history.filter(n=>!n.read).length. timeAgo(t): const diff=Date.now()-t; return diff<60000?Math.floor(diff/1000)+'s ago':diff<3600000?Math.floor(diff/60000)+'m ago':Math.floor(diff/3600000)+'h ago'."
