          hint: "const pool=[{type:'info',title:'...',msg:'...'},{...},...]; let feedTimer=null; function startFeed(){feedTimer=setInterval(()=>{const n=pool[Math.floor(Math.random()*pool.length)];addN(n.type,n.title,n.msg);},5000);} Audio: const ctx=new AudioContext(); function beep(){const o=ctx.createOscillator();const g=ctx.createGain();o.connect(g);g.connect(ctx.destination);o.frequency.value=880;g.gain.setValueAtTime(0.3,ctx.currentTime);g.gain.exponentialRampToValueAtTime(0.001,ctx.currentTime+0.2);o.start();o.stop(ctx.currentTime+0.2);}"
