          difficulty: "Advanced",
          description: "Add a cart drawer that slides in from the right when 'Add to Cart' is clicked (or when the cart icon is clicked). It should list all added items with quantities, allow removing items (with a fade-out animation), show subtotal and estimated tax, and have a 'Checkout' button. The drawer should have a backdrop overlay that closes the drawer on click. Store cart items in an array: [{product, edition, duration, qty, price}]. Support adding the same variant multiple times by incrementing its quantity.",
          hint: "const cart=[]; function addToCart(){const item={...COLORS[selectedColor],duration:SIZES[selectedSize].label,qty}; const existing=cart.find(c=>c.name===item.name&&c.duration===item.duration); if(existing)existing.qty+=item.qty; else cart.push(item); renderCart(); openDrawer();}. Drawer HTML: position:fixed;right:0;top:0;width:360px;height:100vh;transform:translateX(100%);transition:transform 0.3s. Toggle: drawer.style.transform='translateX(0)'."
