    concepts: ["pbkdf2_hmac", "salt", "key stretching", "iterations", "password storage"],
    codeExample: `import hashlib
import secrets

def hash_password(password):
    salt = secrets.token_bytes(16)
    dk = hashlib.pbkdf2_hmac("sha256", password.encode(), salt, 100_000)
    return salt.hex() + ":" + dk.hex()

def verify_password(password, stored):
    salt_hex, dk_hex = stored.split(":")
    salt = bytes.fromhex(salt_hex)
    dk = hashlib.pbkdf2_hmac("sha256", password.encode(), salt, 100_000)
    return secrets.compare_digest(dk.hex(), dk_hex)

stored = hash_password("hunter2")
print("Stored record:", stored[:40], "...")
print("Correct password:", verify_password("hunter2", stored))
print("Wrong password:", verify_password("guess", stored))`,
