    concepts: ["cryptanalysis", "frequency analysis", "brute force", "scoring heuristic", "ctf"],
    codeExample: `ENGLISH_FREQ_ORDER = "etaoinshrdlcumwfgypbvkjxqz"

def decrypt_shift(text, shift):
    out = ""
    for c in text:
        if c.isalpha():
            base = ord('a')
            out += chr((ord(c.lower()) - base - shift) % 26 + base)
        else:
            out += c
    return out

def score(text):
    return sum(ENGLISH_FREQ_ORDER.index(c) for c in text if c.isalpha())

cipher = "Wkh vhfuhw lv vdih"
best = min(range(26), key=lambda s: score(decrypt_shift(cipher, s)))
print("Cipher text:", cipher)
print("Recovered shift:", best)
print("Plaintext:", decrypt_shift(cipher, best))`,
